var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>동결 해제율. 현재 53%.</color>","JPN":"<color=#ffd34c>凍結解除率。現在53％。</color>","ENG":"<color=#ffd34c>Thaw rate... Currently at 53%.</color>","TWN":"<color=#ffd34c>凍結解除率，目前53%。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>개인 역장 해제. 신진대사 활성화 진행 중.</color>","JPN":"<color=#ffd34c>対象の力場解除。新陳代謝活性化進行中。</color>","ENG":"<color=#ffd34c>Removing personal stasis fields. Reactivating metabolic processes.</color>","TWN":"<color=#ffd34c>個人力場解除，代謝活性化進行中。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알렉스!","JPN":"アレックス！","ENG":"Alex!","TWN":"雅蕾克絲！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"발레리! 예고르......!","JPN":"ヴァレリー！　イェゴール……！","ENG":"Valeriy! Yegor!","TWN":"瓦萊里！伊高爾……！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"모두들 살아 있었어...... 그때와 변함없구나......","JPN":"皆、生きていた……あの時と寸分変わらない……","ENG":"You're all still alive... You haven't changed a bit...","TWN":"大家都還活著……和那個時候一點都沒變……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"다시는...... 다시는 너희 얼굴을 못 볼 줄 알았어......","JPN":"もう二度と……お前たちの顔を見ることは叶わないと思っていた……","ENG":"I thought... I thought I'd never get to see you again...","TWN":"我以為……我以為再也見不到你們了……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>경고. 탑승자로부터 말기 침식 증후군 발생 감지.</color>","JPN":"<color=#ffd34c>警告。搭乗者より末期侵食症候群の発生を感知。</color>","ENG":"<color=#ffd34c>Warning. Late stage Corruption syndrome detected among the passengers.</color>","TWN":"<color=#ffd34c>警告，從搭乘者身上檢測出侵蝕症候群末期症狀。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>동결 해제 후 수 시간 내에 대상이 침식체로 변이할 수 있습니다.</color>","JPN":"<color=#ffd34c>凍結解除後、数時間以内に対象が侵食体に変異する可能性があります。</color>","ENG":"<color=#ffd34c>They may turn into a C.O. within hours of removing stasis.</color>","TWN":"<color=#ffd34c>凍結解除後，可能會在幾個小時內變異成侵蝕體。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>안전을 위해 동결 해제 전 즉시 소각을 권장 드립니다.</color>","JPN":"<color=#ffd34c>安全のために凍結解除前の即時焼却を推奨いたします。</color>","ENG":"<color=#ffd34c>Immediate incineration is recommended to ensure safety.</color>","TWN":"<color=#ffd34c>為了安全，建議在凍結解除前立刻焚化。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"뭐......?!","JPN":"何っ……！？","ENG":"What?","TWN":"什麼……？！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"무슨 짓이냐! 이들은 내 대원들이다! 당장 멈춰!","JPN":"何のマネだ！　この者たちは我が隊の隊員だ！　すぐに中止しろ！","ENG":"What are you doing? These are my troops! Stop it at once!","TWN":"幹什麼！他們是我的隊員！立刻住手！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"코핀-6. 소각 처리는 일시 중지한다.","JPN":"コフィン-6。焼却処理は一時停止とする。","ENG":"Coffin-6. Suspend the incineration process.","TWN":"科芬-6. 暫時停止焚化處理。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>관리자 권한 명령 확인.</color>","JPN":"<color=#ffd34c>管理者権限命令確認。</color>","ENG":"<color=#ffd34c>Administrator orders confirmed.</color>","TWN":"<color=#ffd34c>管理者特權的指令確認</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>소각 처리는 보류합니다.</color>","JPN":"<color=#ffd34c>焼却処理は保留いたします。</color>","ENG":"<color=#ffd34c>Suspending incineration.</color>","TWN":"<color=#ffd34c>保留焚化處理。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......관리자님, 방금 그게 다 무슨 말입니까?","JPN":"……管理者様、今の話はどういうことです？","ENG":"What was that about, just now?","TWN":"……管理者大人，剛剛那是什麼意思？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"침식체라니......! 대원들이 왜 침식체로 변이한단 겁니까?!","JPN":"侵食体だなどと……！　なぜ隊員たちが侵食体に変異するのですか！？","ENG":"Corrupted Objects? Why would the troops turn into C.O.s?","TWN":"竟然說侵蝕體……！我的隊員們為什麼會變異成侵蝕體呢？！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"안타깝지만 메이즈 전대원들 모두, 이면세계에 너무 오래 방치되어 있었어.","JPN":"残念だがメイズ戦隊の隊員はみんな、裏世界に長く放置されすぎた。","ENG":"Regrettably, everyone in your unit has been left too long in the Counterside.","TWN":"很遺憾，梅茲戰隊的隊員們在異界待太久了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"함선의 침식 방호 기능이 아무리 좋다고 해도 한계는 오는 법이야.","JPN":"艦船の侵食防護機能がいかに優れていようと、それでも限界はある。","ENG":"Even though the ship is shielded against Corruption, it has its limits.","TWN":"不管艦船的侵蝕防護功能再優秀，它也會有極限。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};